          text="$text → $forecast_icon"
        fi

        # Build tooltip
        tooltip="$desc
    Feels like ''${feels}°C
    Humidity: ''${humidity}%"
        if [ -n "$forecast" ]; then
          tooltip="$tooltip

    $forecast"
        fi

